%#codegen
function y = Pool_fixpt(x)

fm = get_fimath();

[fmo_1, fmo_2, fmo_3] = size(x);
xrow = fi(fmo_1, 0, 5, 0, fm);
xcol = fi(fmo_2, 0, 5, 0, fm);
numFilters = fi(fmo_3, 0, 5, 0, fm);
y = fi(zeros(fi_toint(fi_div_by_shift(xrow, 1)), fi_toint(fi_div_by_shift(xcol, 1)), fi_toint(numFilters)), 0, 16, 14, fm);

for k = fi(1, 0, 1, 0, fm):numFilters
    filter = fi(ones(2) / (2*2), 0, 4, 4, fm);
    %image = conv2(x(:, :, k), filter, 'valid');
    image=fi(my_conv2_valid2(fi(x(:, :, k), 0, 16, 13, fm), fi(rot90(filter), 0, 4, 4, fm)), 0, 16, 14, fm);
    y(:, :, k) = image(1:2:end, 1:2:end);
end
end

function resultado = my_conv2_valid2(x, filtro)

    fm = get_fimath();

    resultado = fi(zeros(19, 19), 0, 16, 14, fm);

    % Aplicar el filtro bidimensional solo en las regiones válidas
    for i = 1:19
        for j = 1:19
            submatriz = fi(x(i:i+1, j:j+1), 0, 16, 13, fm);
            % Realizar la convolución para esta submatriz y almacenar el resultado
            resultado(i, j) = sum(sum(submatriz .* filtro));
        end
    end
end



function y = fi_div_by_shift(a,shift_len)
    coder.inline( 'always' );
    if isfi( a )
        nt = numerictype( a );
        fm = fimath( a );
        nt_bs = numerictype( nt.Signed, nt.WordLength + shift_len, nt.FractionLength + shift_len );
        y = bitsra( fi( a, nt_bs, fm ), shift_len );
    else
        y = a / 2 ^ shift_len;
    end
end


function y = fi_toint(u)
    coder.inline( 'always' );
    if isfi( u )
        nt = numerictype( u );
        s = nt.SignednessBool;
        wl = nt.WordLength;
        y = int32( fi( u, s, wl, 0, hdlfimath ) );
    else
        y = int32( u );
    end
end

function fm = get_fimath()
	fm = fimath('RoundingMethod', 'Zero',...
	     'OverflowAction', 'Wrap',...
	     'ProductMode','FullPrecision',...
	     'SumMode','FullPrecision');
end
